import styled from "styled-components";
import { StyledRegularText } from "../RegularText/index.style";

interface StyledButtonProps {
    bigText?: boolean;
}

const StyledButton = styled.button<StyledButtonProps>`
    background: yellow;
    color: white;

    ${StyledRegularText} {
        color: black;
    }

    ${props => props.bigText && `
        ${StyledRegularText} {
            font-size: 32px;
        }
    `}
`;

export { StyledButton };
